   1→import { createContext, useContext, useReducer } from 'react';
   2→import { createProject } from '@/domain/models';
   3→import { clearProjectPhaseReferences } from '@/domain/phaseAssignments';
   4→import { createDuplicatedFloor, getDefaultFloorName, getFloorElevation, getFloorLevelIndex, shiftFloorAbsoluteElements, shiftFloorElevationData, sortFloors } from '@/domain/floorModels';
   5→import { sortPhases } from '@/domain/phaseModels';
   6→import { getRoofAttachmentElevation, syncProjectRoofSystem } from '@/domain/roofModels';
   7→import { syncProjectTrussSystems } from '@/domain/trussModels';
   8→import { detachColumnAttachments, syncWallAttachmentPoints } from '@/geometry/wallColumnGeometry';
   9→import { syncStairLandingAttachment } from '@/geometry/landingGeometry';
  10→import { clampWallOpeningOffset, wallLength } from '@/geometry/wallGeometry';
  11→
  12→const ProjectContext = createContext(null);
  13→const HISTORY_LIMIT = 100;
  14→
  15→function snapshotProject(project) {
  16→  return JSON.stringify(project);
  17→}
  18→
  19→function syncProjectStructures(project) {
  20→  return syncProjectRoofSystem(syncProjectTrussSystems(project));
  21→}
  22→
  23→function applyProjectUpdate(state, nextProject, recordHistory = true) {
  24→  const syncedProject = syncProjectStructures(nextProject);
  25→  const nextSnapshot = snapshotProject(syncedProject);
  26→  const history = recordHistory
  27→    ? [...state.history, state.project].slice(-HISTORY_LIMIT)
  28→    : state.history;
  29→
  30→  return {
  31→    ...state,
  32→    history,
  33→    future: recordHistory ? [] : state.future,
  34→    project: syncedProject,
  35→    isDirty: nextSnapshot !== state.savedSnapshot,
  36→  };
  37→}
  38→
  39→function updateFloor(state, floorId, updater, recordHistory = true, options = {}) {
  40→  const nextFloors = state.project.floors.map((floor) => (
  41→    floor.id === floorId ? updater(floor) : floor
  42→  ));
  43→
  44→  return applyProjectUpdate(state, {
  45→    ...state.project,
  46→    updatedAt: new Date().toISOString(),
  47→    floors: options.sort ? sortFloors(nextFloors) : nextFloors,
  48→  }, recordHistory);
  49→}
  50→
  51→function replaceFloors(state, floors, recordHistory = true) {
  52→  return applyProjectUpdate(state, {
  53→    ...state.project,
  54→    updatedAt: new Date().toISOString(),
  55→    floors: sortFloors(floors),
  56→  }, recordHistory);
  57→}
  58→
  59→function replaceDeletedFloorReferences(project, deletedFloorId, fallbackFloorId) {
  60→  return {
  61→    ...project,
  62→    floors: project.floors.map((floor) => ({
  63→      ...floor,
  64→      stairs: (floor.stairs || []).map((stair) => ({
  65→        ...stair,
  66→        floorRelation: {
  67→          fromFloorId: stair.floorRelation?.fromFloorId === deletedFloorId
  68→            ? fallbackFloorId
  69→            : (stair.floorRelation?.fromFloorId ?? floor.id),
  70→          toFloorId: stair.floorRelation?.toFloorId === deletedFloorId
  71→            ? fallbackFloorId
  72→            : (stair.floorRelation?.toFloorId ?? floor.id),
  73→        },
  74→      })),
  75→    })),
  76→    sheets: (project.sheets || []).map((sheet) => ({
  77→      ...sheet,
  78→      viewports: (sheet.viewports || []).map((viewport) => ({
  79→        ...viewport,
  80→        sourceFloorId: viewport.sourceFloorId === deletedFloorId
  81→          ? fallbackFloorId
  82→          : viewport.sourceFloorId,
  83→        sourceRefId: viewport.sourceFloorId === deletedFloorId
  84→          ? null
  85→          : viewport.sourceRefId,
  86→      })),
  87→    })),
  88→  };
  89→}
  90→
  91→function clearStairRoofAccessReferences(project, roofOpeningId = null) {
  92→  return {
